class ErrorSeverity(Enum):
    LOW = "LOW"
    MEDIUM = "MEDIUM"
    HIGH = "HIGH"
    CRITICAL = "CRITICAL"


class SecureErrorHandler:
    def __init__(self, include_stack_trace=False, include_internal_state=False, 
                 sanitize_sensitive_data=True):
        self.include_stack_trace = include_stack_trace
        self.include_internal_state = include_internal_state
        self.sanitize_sensitive_data = sanitize_sensitive_data
        self.sensitive_keys = {'password', 'token', 'secret', 'api_key', 'auth', 
                              'credential', 'private_key', 'session_id'}
    
    def sanitize_data(self, data):
        if not self.sanitize_sensitive_data:
            return data
        
        if isinstance(data, dict):
            sanitized = {}
            for key, value in data.items():
                if any(sensitive in key.lower() for sensitive in self.sensitive_keys):
                    sanitized[key] = "***REDACTED***"
                elif isinstance(value, (dict, list)):
                    sanitized[key] = self.sanitize_data(value)
                else:
                    sanitized[key] = value
            return sanitized
        elif isinstance(data, list):
            return [self.sanitize_data(item) for item in data]
        return data
    
    def get_error_details(self, exception, context_data=None, severity=ErrorSeverity.MEDIUM):
        error_info = {
            "timestamp": datetime.utcnow().isoformat(),
            "error_type": type(exception).__name__,
            "error_message": str(exception),
            "severity": severity.value
        }
        
        if self.include_stack_trace:
            tb_lines = traceback.format_exception(type(exception), exception, 
                                                  exception.__traceback__)
            error_info["stack_trace"] = self.sanitize_stack_trace(tb_lines)
        
        if self.include_internal_state and context_data:
            error_info["internal_state"] = self.sanitize_data(context_data)
        
        return json.dumps(error_info, indent=2)
    
    def sanitize_stack_trace(self, tb_lines):
        sanitized_lines = []
        for line in tb_lines:
            sanitized_line = line
            for sensitive in self.sensitive_keys:
                if sensitive in line.lower():
                    parts = line.split('=')
                    if len(parts) > 1:
                        sanitized_line = parts[0] + '=***REDACTED***'
            sanitized_lines.append(sanitized_line)
        return ''.join(sanitized_lines)


def handle_grpc_errors(error_handler=None, severity=ErrorSeverity.MEDIUM):
    if error_handler is None:
        error_handler = SecureErrorHandler(
            include_stack_trace=False,
            include_internal_state=False,
            sanitize_sensitive_data=True
        )
    
    def decorator(func):
        def wrapper(self, request, context):
            try:
                return func(self, request, context)
            
            except grpc.RpcError as e:
                logger.error(f"gRPC error in {func.__name__}: {str(e)}")
                context.set_code(e.code())
                error_details = error_handler.get_error_details(
                    e, 
                    {"method": func.__name__, "request_type": type(request).__name__},
                    severity
                )
                context.set_details(error_details)
                return None
            
            except ValueError as e:
                logger.error(f"Validation error in {func.__name__}: {str(e)}")
                context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
                error_details = error_handler.get_error_details(
                    e,
                    {"method": func.__name__, "validation_failed": True},
                    ErrorSeverity.LOW
                )
                context.set_details(error_details)
                return None
            
            except PermissionError as e:
                logger.error(f"Permission error in {func.__name__}: {str(e)}")
                context.set_code(grpc.StatusCode.PERMISSION_DENIED)
                error_details = error_handler.get_error_details(
                    e,
                    {"method": func.__name__, "access_denied": True},
                    ErrorSeverity.HIGH
                )
                context.set_details(error_details)
                return None
            
            except FileNotFoundError as e:
                logger.error(f"Resource not found in {func.__name__}: {str(e)}")
                context.set_code(grpc.StatusCode.NOT_FOUND)
                error_details = error_handler.get_error_details(
                    e,
                    {"method": func.__name__, "resource_missing": True},
                    ErrorSeverity.MEDIUM
                )
                context.set_details(error_details)
                return None
            
            except TimeoutError as e:
                logger.error(f"Timeout in {func.__name__}: {str(e)}")
                context.set_code(grpc.StatusCode.DEADLINE_EXCEEDED)
                error_details = error_handler.get_error_details(
                    e,
                    {"method": func.__name__, "timeout_occurred": True},
                    ErrorSeverity.HIGH
                )
                context.set_details(error_details)
                return None
            
            except ConnectionError as e:
                logger.error(f"Connection error in {func.__name__}: {str(e)}")
                context.set_code(grpc.StatusCode.UNAVAILABLE)
                error_details = error_handler.get_error_details(
                    e,
                    {"method": func.__name__, "connection_failed": True},
                    ErrorSeverity.CRITICAL
                )
                context.set_details(error_details)
                return None
            
            except Exception as e:
                logger.exception(f"Unexpected error in {func.__name__}: {str(e)}")
                context.set_code(grpc.StatusCode.INTERNAL)
                
                context_data = {
                    "method": func.__name__,
                    "request_type": type(request).__name__,
                    "unexpected_error": True
                }
                
                error_details = error_handler.get_error_details(
                    e,
                    context_data,
                    ErrorSeverity.CRITICAL
                )
                context.set_details(error_details)
                return None
        
        return wrapper
    return decorator


class ExampleService:
    def __init__(self, debug_mode=False):
        self.debug_mode = debug_mode
        self.error_handler = SecureErrorHandler(
            include_stack_trace=debug_mode,
            include_internal_state=debug_mode,
            sanitize_sensitive_data=not debug_mode
        )
        self.internal_state = {
            "service_version": "1.0.0",
            "initialized_at": datetime.utcnow().isoformat()
        }
    
    @handle_grpc_errors()
    def ProcessRequest(self, request, context):
        logger.info(f"Processing request: {request}")
        
        if not hasattr(request, 'data'):
            raise ValueError("Request must contain 'data' field")
        
        if request.data == "trigger_error":
            raise RuntimeError("Simulated error for testing")
        
        response = type('Response', (), {})()
        response.result = f"Processed: {request.data}"
        return response
    
    @handle_grpc_errors()
    def ValidateInput(self, request, context):
        if not request.value or len(request.value) < 3:
            raise ValueError("Input value must be at least 3 characters long")
        
        response = type('Response', (), {})()
        response.valid = True
        return response
    
    @handle_grpc_errors()
    def SecureOperation(self, request, context):
        user_role = getattr(request, 'user_role', None)
        
        if user_role != 'admin':
            raise PermissionError("Only admin users can perform this operation")
        
        response = type('Response', (), {})()
        response.success = True
        return response
    
    @handle_grpc_errors()
    def DatabaseOperation(self, request, context):
        resource_id = getattr(request, 'resource_id', None)
        
        if resource_id == 'nonexistent':
            raise FileNotFoundError(f"Resource with ID '{resource_id}' not found")
        
        response = type('Response', (), {})()
        response.data = f"Resource {resource_id} retrieved"
        return response
    
    @handle_grpc_errors()
    def ExternalServiceCall(self, request, context):
        service_name = getattr(request, 'service_name', None)
        
        if service_name == 'unavailable':
            raise ConnectionError(f"Unable to connect to service: {service_name}")
        
        response = type('Response', (), {})()
        response.result = f"Called {service_name} successfully"
        return response


class MonitoredService:
    def __init__(self):
        self.request_count = 0
        self.error_count = 0
        self.error_handler = SecureErrorHandler(
            include_stack_trace=True,
            include_internal_state=True,
            sanitize_sensitive_data=True
        )
    
    @handle_grpc_errors()
    def MonitoredMethod(self, request, context):
        self.request_count += 1
        
        try:
            if request.should_fail:
                raise RuntimeError("Intentional failure for monitoring")
            
            response = type('Response', (), {})()
            response.count = self.request_count
            return response
        
        except Exception as e:
            self.error_count += 1
            raise


